def solve(arg1: dict) -> dict:
    member_id = arg1.get('member_id')
    challenge_id = arg1.get('challenge_id')
    submitted = arg1.get('submitted', False)

    # Mock data for demonstration purposes
    challenge_status = {
        '67890': {'is_closed': False, 'valid_members': ['12345'], 'submissions': ['submission1', 'submission2', 'submission3']}
    }

    if challenge_id not in challenge_status:
        return {'can_download': False}

    challenge_info = challenge_status[challenge_id]

    if not submitted:
        return {'can_download': False}

    if member_id not in challenge_info['valid_members']:
        return {'can_download': False}

    if challenge_info['is_closed']:
        return {'can_download': True}

    return {
        'can_download': True,
        'downloadable_submissions': challenge_info['submissions']
    }
